Answer_version_1:
SELECT 
    (COUNT(CASE WHEN voucher_amount > 0 THEN 1 END) / COUNT(*)) * 100 AS percentage_with_voucher
FROM `momovn-mimir.MIMIR.iDeA_TRANS_CORE`;

Answer_version_2:
SELECT COUNT(*) AS transaction_count
FROM `momovn-mimir.MIMIR.DLS_ALL_TRANS_V3_1`
WHERE DATE = '2024-09-26' AND SERVICE_CODE = 'Facebook ads';
